    // Snapshot the parent by value first (ClientRegions is Copy) so we never
    // hold two live borrows into TABLE at once.
    let parent = *client_ref(parent_nr).ok_or(EINVAL)?;
    *client_mut(child_nr).ok_or(EINVAL)? = parent;
    Ok(())
}

