    fn munmap_caps_sweep_to_region_end() {
        let mut c = ClientRegions::EMPTY;
        let a = c.mmap(0x1000).unwrap();
        // Caller overstates len; the sweep must not exceed the region's own end.
        let (start, end) = c.munmap(a, 0x4000).unwrap();
