183	fn handle_brk(msg: &mut Message) {
184	    let caller_e = msg.m_source;
185	    let nr = endpoint_proc(caller_e).get();
186	    let new_break = rd_u64(msg, 0);
187	
188	    let reply_type = match region::set_brk(nr, new_break) {
189	        Ok(brk) => {
190	            wr_u64(msg, 0, brk);
191	            OK
192	        }
193	        Err(e) => e,
194	    };
195	
196	    msg.m_type = reply_type;
197	    msg.m_source = 0; // kernel overwrites on delivery
198	    let _ = ipc_send(caller_e, msg);
199	}
200	
201	/// Handle a `VM_MMAP` request: allocate an anonymous region of `len` bytes
202	/// (payload `0..8`), letting VM choose the base address. No frames are mapped
203	/// here — pages fault in lazily and are satisfied by [`handle_pagefault`] via
204	/// the region check. Reply (the caller issued a SENDREC) with `m_type = OK` and
205	/// the chosen base in payload `0..8`, or the negative error in `m_type`.
206	fn handle_mmap(msg: &mut Message) {
207	    let caller_e = msg.m_source;
208	    let nr = endpoint_proc(caller_e).get();
209	    let len = rd_u64(msg, 0);
210	
211	    let reply_type = match region::mmap(nr, len) {
212	        Ok(addr) => {
213	            wr_u64(msg, 0, addr);
214	            OK
215	        }
216	        Err(e) => e,
217	    };
218	
219	    msg.m_type = reply_type;
220	    msg.m_source = 0; // kernel overwrites on delivery
221	    let _ = ipc_send(caller_e, msg);
222	}
223	
224	/// Handle a `VM_MUNMAP` request: drop the caller's mmap region based at `addr`
225	/// (payload `0..8`) covering `len` bytes (payload `8..16`), then unmap each
226	/// backing page. [`region::munmap`] returns the page-aligned `[start, end)`
227	/// snapshot to sweep and marks the slot free *before* we touch the page tables,
228	/// so the loop runs off owned values, not a re-read of the region. A page that
229	/// never faulted in was never mapped, so the kernel returns `EINVAL` for it —
230	/// harmless, ignored (same as unmapping a hole). Reply with `m_type = OK`, or
231	/// `EINVAL` if no region matched (nothing is unmapped in that case).
232	fn handle_munmap(system: Endpoint, msg: &mut Message) {
233	    let caller_e = msg.m_source;
234	    let nr = endpoint_proc(caller_e).get();
235	    let addr = rd_u64(msg, 0);
236	    let len = rd_u64(msg, 8);
237	
238	    let reply_type = match region::munmap(nr, addr, len) {
239	        Ok((start, end)) => {
240	            let mut page = start;
241	            while page < end {
242	                let mut m = Message {
243	                    m_source: 0,
244	                    m_type: SYS_VMCTL,
