1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! PM's process table (slice 4.5) — the minix.rs `mproc`.
4	//!
5	//! Modeled on MINIX 3 `servers/pm/mproc.h`: a static table indexed by the
6	//! *same* process number as the kernel's proc table, each entry carrying the
7	//! POSIX-visible identity (pid, parent) the kernel deliberately knows nothing
8	//! about. MINIX seeds it from `sys_getimage`; minix.rs seeds it from the
9	//! shared boot-image constants in `kernel-shared::com` — same information,
10	//! no kernel call needed while the boot layout is static.
11	//!
12	//! Seeding (mirrors MINIX `pm_init`): PM is pid 0 and its own parent; INIT is
13	//! pid 1; every other boot server takes the next free pid in slot order with
14	//! RS as parent (RS itself is parented to PM so no server is its own
15	//! ancestor); the Phase-4 demo stubs are ordinary user processes parented to
16	//! INIT. Boot servers carry [`MF_PRIV_PROC`], which the kill path refuses to
17	//! terminate — delivering signals *to* system processes (MINIX's sig2mess)
18	//! waits for a consumer (RS restarts).
19	//!
20	//! Table shape follows `vm/region.rs` / `ds/registry.rs`: a fixed-capacity
21	//! `UnsafeCell` static behind a `#[repr(transparent)]` newtype, with all
22	//! logic in pure `*_in` helpers that carry the host unit tests; the thin
23	//! wrappers reaching the static are the only `unsafe`.
24	
25	use core::cell::UnsafeCell;
26	
27	use minixrs_kernel_shared::com::{
28	    INIT_PROC_NR, NR_BOOT_PROCS, NR_STUB_PROCS, PM_PROC_NR, RS_PROC_NR,
29	};
30	
31	/// Table capacity. Slots `0..NR_BOOT_PROCS + NR_STUB_PROCS` (= 16) are seeded
32	/// at init; the headroom is for slice 4.6's fork.
33	pub const NR_MPROCS: usize = 32;
34	
35	/// Entry holds a live process.
36	pub const MF_IN_USE: u8 = 1 << 0;
37	/// Boot system process — the kill path refuses to terminate it.
38	pub const MF_PRIV_PROC: u8 = 1 << 1;
39	/// Terminated by the kill path. The slot is kept (not reusable) until 4.6's
40	/// exit/wait lands zombie + reap semantics.
41	pub const MF_DEAD: u8 = 1 << 2;
42	
43	/// One `mproc` entry. The slot index *is* the kernel proc number; the
44	/// endpoint is derivable as `boot_endpoint(slot)` while everything is
45	/// generation 0 (4.6's fork adds generations and will store endpoints).
46	#[derive(Clone, Copy)]
47	pub struct MProc {
48	    pub pid: i32,
49	    pub parent_slot: usize,
50	    pub flags: u8,
51	}
52	
53	impl MProc {
54	    pub const EMPTY: Self = Self {
55	        pid: 0,
56	        parent_slot: 0,
57	        flags: 0,
58	    };
59	}
60	
61	/// Disposition of a kill request against a slot.
62	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
63	pub enum KillAction {
64	    /// Ordinary user process: caller should terminate it (`SYS_EXIT`).
65	    Terminate,
66	    /// Boot system process: refuse — sig2mess is a later slice.
67	    SkipPrivileged,
68	    /// Unknown, unused, or already-dead slot: nothing to do.
69	    NotFound,
70	}
71	
72	/// Seed the table with the boot image + demo stubs. Pure; called once from
73	/// PM's SEF init via [`seed`].
74	fn seed_in(t: &mut [MProc; NR_MPROCS]) {
75	    let pm = PM_PROC_NR.get() as usize;
76	    let rs = RS_PROC_NR.get() as usize;
77	    let init = INIT_PROC_NR.get() as usize;
78	
79	    // PM: pid 0, its own parent (MINIX `pm_init` patches itself the same way).
80	    t[pm] = MProc {
81	        pid: 0,
82	        parent_slot: pm,
83	        flags: MF_IN_USE | MF_PRIV_PROC,
84	    };
85	    // INIT: pid 1. Not running yet (no ELF until 4.8) but seeded so the demo
86	    // stubs have a parent with a pid.
87	    t[init] = MProc {
88	        pid: 1,
89	        parent_slot: rs,
90	        flags: MF_IN_USE | MF_PRIV_PROC,
91	    };
92	
93	    // Remaining boot servers: next free pids in slot order, parented to RS
94	    // (the root system process) — except RS itself, parented to PM so no
95	    // process is its own ancestor besides PM.
96	    let mut next_pid = 2;
97	    for (slot, e) in t.iter_mut().enumerate().take(NR_BOOT_PROCS) {
98	        if slot == pm || slot == init {
99	            continue;
100	        }
101	        *e = MProc {
102	            pid: next_pid,
103	            parent_slot: if slot == rs { pm } else { rs },
104	            flags: MF_IN_USE | MF_PRIV_PROC,
105	        };
106	        next_pid += 1;
107	    }
108	
109	    // Demo stubs: ordinary user processes, parented to INIT, pids continuing
110	    // past the servers (slots 11..=15 land on pids 11..=15).
111	    for e in t.iter_mut().skip(NR_BOOT_PROCS).take(NR_STUB_PROCS) {
112	        *e = MProc {
113	            pid: next_pid,
114	            parent_slot: init,
115	            flags: MF_IN_USE,
116	        };
117	        next_pid += 1;
118	    }
119	}
120	
121	/// Look up `(pid, ppid)` for `slot`. `None` for out-of-range, unused, or dead
122	/// slots — the caller replies `ESRCH`.
123	fn getpid_in(t: &[MProc; NR_MPROCS], slot: usize) -> Option<(i32, i32)> {
124	    let e = t.get(slot)?;
125	    if e.flags & MF_IN_USE == 0 || e.flags & MF_DEAD != 0 {
126	        return None;
127	    }
128	    Some((e.pid, t[e.parent_slot].pid))
129	}
130	
131	/// Decide the kill disposition for `slot` and, when it is an ordinary live
132	/// user process, mark it dead. The caller performs the actual `SYS_EXIT`.
133	fn handle_kill_in(t: &mut [MProc; NR_MPROCS], slot: usize) -> KillAction {
134	    let Some(e) = t.get_mut(slot) else {
135	        return KillAction::NotFound;
136	    };
137	    if e.flags & MF_IN_USE == 0 || e.flags & MF_DEAD != 0 {
138	        return KillAction::NotFound;
139	    }
140	    if e.flags & MF_PRIV_PROC != 0 {
141	        return KillAction::SkipPrivileged;
142	    }
143	    e.flags |= MF_DEAD;
144	    KillAction::Terminate
145	}
146	
147	/// `UnsafeCell`-wrapped static table. See the module note for the
148	/// single-mutator invariant that makes the `Sync` impl sound.
149	#[repr(transparent)]
150	struct Table(UnsafeCell<[MProc; NR_MPROCS]>);
151	
152	// SAFETY: PM is a single-threaded EL0 process with no interrupt handlers of
153	// its own; the table is only ever accessed from PM's straight-line SEF
154	// init + receive loop, so there is never concurrent access.
155	unsafe impl Sync for Table {}
156	
157	static TABLE: Table = Table(UnsafeCell::new([MProc::EMPTY; NR_MPROCS]));
158	
159	/// Seed the global table from the boot-image constants.
160	pub fn seed() {
161	    // SAFETY: single-mutator invariant (module note); no other reference into
162	    // the table is live during PM's straight-line init.
163	    let t = unsafe { &mut *TABLE.0.get() };
164	    seed_in(t);
165	}
166	
167	/// Look up `(pid, ppid)` for `slot` in the global table.
168	pub fn getpid(slot: usize) -> Option<(i32, i32)> {
169	    // SAFETY: single-mutator invariant (module note); shared read, no live `&mut`.
170	    let t = unsafe { &*TABLE.0.get() };
171	    getpid_in(t, slot)
172	}
173	
174	/// Decide (and record) the kill disposition for `slot` in the global table.
175	pub fn handle_kill(slot: usize) -> KillAction {
176	    // SAFETY: single-mutator invariant (module note); no other reference into
177	    // the table is live during PM's straight-line loop.
178	    let t = unsafe { &mut *TABLE.0.get() };
179	    handle_kill_in(t, slot)
180	}
181	
182	#[cfg(test)]
183	mod tests {
184	    use super::*;
185	    use minixrs_kernel_shared::com::{
186	        SCHED_PROC_NR, STUB_A_PROC_NR, STUB_D_PROC_NR, STUB_E_PROC_NR, VFS_PROC_NR, VM_PROC_NR,
187	    };
188	
189	    fn seeded() -> [MProc; NR_MPROCS] {
190	        let mut t = [MProc::EMPTY; NR_MPROCS];
191	        seed_in(&mut t);
192	        t
193	    }
194	
195	    #[test]
196	    fn seed_assigns_boot_pids() {
197	        let t = seeded();
198	        // PM pid 0, INIT pid 1, then slot order: VFS(1)=2, RS(2)=3 … SCHED(9)=10.
199	        assert_eq!(t[PM_PROC_NR.get() as usize].pid, 0);
200	        assert_eq!(t[INIT_PROC_NR.get() as usize].pid, 1);
201	        assert_eq!(t[VFS_PROC_NR.get() as usize].pid, 2);
202	        assert_eq!(t[RS_PROC_NR.get() as usize].pid, 3);
203	        assert_eq!(t[VM_PROC_NR.get() as usize].pid, 8);
204	        assert_eq!(t[SCHED_PROC_NR.get() as usize].pid, 10);
205	        for (slot, e) in t.iter().enumerate().take(NR_BOOT_PROCS) {
206	            assert_eq!(e.flags, MF_IN_USE | MF_PRIV_PROC, "slot {slot}");
207	        }
208	    }
209	
210	    #[test]
211	    fn seed_stub_pids_continue() {
212	        let t = seeded();
213	        for (i, slot) in (NR_BOOT_PROCS..NR_BOOT_PROCS + NR_STUB_PROCS).enumerate() {
214	            assert_eq!(t[slot].pid, 11 + i as i32);
215	            assert_eq!(t[slot].flags, MF_IN_USE, "stubs are not PRIV_PROC");
216	            assert_eq!(t[slot].parent_slot, INIT_PROC_NR.get() as usize);
217	        }
218	    }
219	
220	    #[test]
221	    fn seed_pids_are_unique() {
222	        let t = seeded();
223	        let mut seen = [false; 64];
224	        for e in t.iter().filter(|e| e.flags & MF_IN_USE != 0) {
225	            let pid = e.pid as usize;
226	            assert!(!seen[pid], "duplicate pid {pid}");
227	            seen[pid] = true;
228	        }
229	    }
230	
231	    #[test]
232	    fn getpid_returns_pid_and_ppid() {
233	        let t = seeded();
234	        // PM is its own parent: (0, 0).
235	        assert_eq!(getpid_in(&t, PM_PROC_NR.get() as usize), Some((0, 0)));
236	        // VM's parent is RS (pid 3).
237	        assert_eq!(getpid_in(&t, VM_PROC_NR.get() as usize), Some((8, 3)));
238	        // Stubs are parented to INIT (pid 1).
239	        assert_eq!(getpid_in(&t, STUB_A_PROC_NR.get() as usize), Some((11, 1)));
240	        assert_eq!(getpid_in(&t, STUB_E_PROC_NR.get() as usize), Some((15, 1)));
241	    }
242	
243	    #[test]
244	    fn getpid_unknown_slot_is_none() {
245	        let t = seeded();
246	        assert_eq!(getpid_in(&t, 16), None, "unseeded slot");
247	        assert_eq!(getpid_in(&t, NR_MPROCS), None, "out of range");
248	    }
249	
250	    #[test]
251	    fn getpid_dead_slot_is_none() {
252	        let mut t = seeded();
253	        let d = STUB_D_PROC_NR.get() as usize;
254	        assert_eq!(handle_kill_in(&mut t, d), KillAction::Terminate);
255	        assert_eq!(getpid_in(&t, d), None, "terminated proc has no pid");
256	    }
257	
258	    #[test]
259	    fn kill_user_proc_terminates_and_marks_dead() {
260	        let mut t = seeded();
261	        let d = STUB_D_PROC_NR.get() as usize;
262	        assert_eq!(handle_kill_in(&mut t, d), KillAction::Terminate);
263	        assert_ne!(t[d].flags & MF_DEAD, 0);
264	    }
265	
266	    #[test]
267	    fn kill_priv_proc_is_skipped() {
268	        let mut t = seeded();
269	        let vm = VM_PROC_NR.get() as usize;
270	        assert_eq!(handle_kill_in(&mut t, vm), KillAction::SkipPrivileged);
271	        assert_eq!(t[vm].flags & MF_DEAD, 0, "server must not be marked dead");
272	    }
273	
274	    #[test]
275	    fn kill_dead_or_unknown_is_notfound() {
276	        let mut t = seeded();
277	        let d = STUB_D_PROC_NR.get() as usize;
278	        assert_eq!(handle_kill_in(&mut t, d), KillAction::Terminate);
279	        // A second kill on the same (now dead) slot finds nothing to do.
280	        assert_eq!(handle_kill_in(&mut t, d), KillAction::NotFound);
281	        assert_eq!(handle_kill_in(&mut t, 20), KillAction::NotFound);
282	        assert_eq!(handle_kill_in(&mut t, NR_MPROCS), KillAction::NotFound);
283	    }
284	}
